<template>
  <view class="page result-page">
    <!-- Payment Status Icon Card -->
    <view class="section result-card">
      <view
        class="status-circle"
        :class="payment.paymentStatus === 'SUCCESS' ? 'success' : 'pending'"
      >
        <text v-if="payment.paymentStatus === 'SUCCESS'" class="status-emoji">✓</text>
        <text v-else class="status-emoji">⏳</text>
      </view>

      <view class="result-title">{{
        paymentStatusText[payment.paymentStatus] || '支付处理中'
      }}</view>
      <view class="result-subtitle">担保服务费支付流水单据已生成，请核对支付详情。</view>
    </view>

    <!-- Receipt Details Card -->
    <view class="section receipt-card">
      <view class="section-title">支付流水信息</view>

      <view class="receipt-list">
        <view class="receipt-row">
          <text class="receipt-lbl">担保服务费用</text>
          <text class="receipt-val price">{{ yuanText(payment.amountCent) }}</text>
        </view>
        <view class="receipt-row">
          <text class="receipt-lbl">服务费用途</text>
          <text class="receipt-val">订单线上担保履约服务</text>
        </view>
        <view class="receipt-row">
          <text class="receipt-lbl">商户订单号</text>
          <text class="receipt-val font-mono">{{ payment.merchantOrderNo || '-' }}</text>
        </view>
        <view class="receipt-row">
          <text class="receipt-lbl">微信交易流水</text>
          <text class="receipt-val font-mono">{{ payment.transactionNo || '-' }}</text>
        </view>
      </view>
    </view>

    <!-- Guide Alert -->
    <view class="section alert-guide-card">
      <view class="alert-title">💡 下一步做什么？</view>
      <view class="alert-desc">
        我们已将该订单推送给承运商确认。承运商确认并签署托运合同后，即可安排司机上门提车。您可以在订单详情中跟踪运输全流程。
      </view>
    </view>

    <!-- Sticky Footer Actions -->
    <view class="fixed-footer result-footer-actions">
      <button class="primary-btn footer-btn" @click="goDetail">进入订单详情</button>
      <button class="plain-btn footer-btn mt-3" @click="goHome">返回系统首页</button>
    </view>
  </view>
</template>

<script>
import { api, requireLogin } from '../../utils/api.js';
import { paymentStatusText, yuanText } from '../../utils/format.js';

export default {
  data() {
    return {
      orderId: '',
      paymentId: '',
      payment: {},
      paymentStatusText,
    };
  },
  onLoad(options) {
    if (!requireLogin()) return;
    this.orderId = options.orderId;
    this.paymentId = options.paymentId;
    this.load();
  },
  methods: {
    yuanText,
    async load() {
      this.payment = await api.payment(this.paymentId);
    },
    goDetail() {
      uni.redirectTo({ url: `/pages/order/detail?orderId=${this.orderId}` });
    },
    goHome() {
      uni.switchTab({ url: '/pages/home/index' });
    },
  },
};
</script>

